insert into hadith_topics (topic_bn, hadith_text_bn, reference, importance_tag) values
('নিয়ত ও ইখলাস', 'রাসূলুল্লাহ (সা.) বলেছেন, সমস্ত আমল নিয়তের উপর নির্ভরশীল, আর প্রত্যেক ব্যক্তি তার নিয়ত অনুযায়ীই প্রতিদান পাবে।', 'সহীহ বুখারী, হাদীস নং ১; সহীহ মুসলিম, হাদীস নং ১৯০৭', 'অপরিহার্য'),
('ভ্রাতৃত্ব ও ভালোবাসা', 'রাসূলুল্লাহ (সা.) বলেছেন, তোমাদের কেউ ততক্ষণ পর্যন্ত (পরিপূর্ণ) মুমিন হতে পারবে না, যতক্ষণ না নিজের জন্য যা পছন্দ করে, তার ভাইয়ের জন্যও তা পছন্দ করে।', 'সহীহ বুখারী, হাদীস নং ১৩; সহীহ মুসলিম, হাদীস নং ৪৫', 'অপরিহার্য'),
('প্রতিবেশী, মেহমান ও সদালাপ', 'রাসূলুল্লাহ (সা.) বলেছেন, যে আল্লাহ ও পরকালে বিশ্বাস করে, সে যেন প্রতিবেশীকে কষ্ট না দেয়; যে আল্লাহ ও পরকালে বিশ্বাস করে, সে যেন মেহমানের সম্মান করে; আর যে আল্লাহ ও পরকালে বিশ্বাস করে, সে যেন ভালো কথা বলে অথবা চুপ থাকে।', 'সহীহ বুখারী, হাদীস নং ৬০১৮; সহীহ মুসলিম, হাদীস নং ৪৭', 'গুরুত্বপূর্ণ'),
('রাগ নিয়ন্ত্রণ', 'রাসূলুল্লাহ (সা.) বলেছেন, শক্তিশালী ব্যক্তি সে নয় যে কুস্তিতে (কাউকে) পরাজিত করে, প্রকৃত শক্তিশালী সে-ই যে রাগের সময় নিজেকে নিয়ন্ত্রণ করতে পারে।', 'সহীহ বুখারী, হাদীস নং ৬১১৪; সহীহ মুসলিম, হাদীস নং ২৬০৯', 'গুরুত্বপূর্ণ'),
('হাসিমুখে কথা বলা', 'রাসূলুল্লাহ (সা.) বলেছেন, তোমার ভাইয়ের সামনে হাসিমুখে কথা বলাও একটি সাদাকা।', 'জামি'' আত-তিরমিযী, হাদীস নং ১৯৫৬', 'মাঝারি'),
('জ্ঞান অন্বেষণ', 'রাসূলুল্লাহ (সা.) বলেছেন, যে ব্যক্তি জ্ঞান অন্বেষণের পথে চলে, আল্লাহ তার জন্য জান্নাতের পথ সহজ করে দেন।', 'সহীহ মুসলিম, হাদীস নং ২৬৯৯', 'গুরুত্বপূর্ণ'),
('সততা ও মিথ্যা পরিহার', 'রাসূলুল্লাহ (সা.) বলেছেন, সত্যবাদিতা মানুষকে নেক আমলের দিকে পরিচালিত করে, আর নেক আমল জান্নাতের দিকে নিয়ে যায়। পক্ষান্তরে মিথ্যা পাপাচারের দিকে পরিচালিত করে, আর পাপাচার জাহান্নামের দিকে নিয়ে যায়।', 'সহীহ বুখারী, হাদীস নং ৬০৯৪; সহীহ মুসলিম, হাদীস নং ২৬০৭', 'অপরিহার্য'),
('স্ত্রীর সাথে উত্তম আচরণ', 'রাসূলুল্লাহ (সা.) বলেছেন, তোমাদের মধ্যে সর্বোত্তম ব্যক্তি সে-ই, যে তার স্ত্রীর প্রতি সর্বোত্তম আচরণ করে।', 'জামি'' আত-তিরমিযী, হাদীস নং ৩৮৯৫', 'গুরুত্বপূর্ণ'),
('দয়া ও করুণা', 'রাসূলুল্লাহ (সা.) বলেছেন, যারা দয়ালু, পরম দয়ালু আল্লাহ তাদের প্রতি দয়া করেন। তোমরা পৃথিবীতে যাদের প্রতি দয়া করবে, আসমানে যিনি আছেন তিনি তোমাদের প্রতি দয়া করবেন।', 'সুনানে আবু দাউদ, হাদীস নং ৪৯৪১; জামি'' আত-তিরমিযী, হাদীস নং ১৯২৪', 'গুরুত্বপূর্ণ'),
('সামাজিক দায়িত্ব', 'রাসূলুল্লাহ (সা.) বলেছেন, রাস্তা থেকে কষ্টদায়ক কোনো বস্তু সরিয়ে ফেলাও একটি সাদাকা।', 'সহীহ বুখারী, হাদীস নং ২৯৮৯; সহীহ মুসলিম, হাদীস নং ১০০৯', 'মাঝারি'),
('ধৈর্যের ফযীলত', 'রাসূলুল্লাহ (সা.) বলেছেন, যে ধৈর্য ধারণ করতে চায়, আল্লাহ তাকে ধৈর্যশীল বানিয়ে দেন। আর ধৈর্যের চেয়ে ব্যাপক ও উত্তম কোনো নিয়ামত কাউকে দেয়া হয়নি।', 'সহীহ বুখারী, হাদীস নং ১৪৬৯; সহীহ মুসলিম, হাদীস নং ১০৫৩', 'গুরুত্বপূর্ণ'),
('পাঁচ ওয়াক্ত সালাতের গুরুত্ব', 'রাসূলুল্লাহ (সা.) সাহাবীদের জিজ্ঞাসা করলেন, তোমাদের কারো দরজার সামনে যদি একটি নদী থাকে আর সে তাতে দিনে পাঁচবার গোসল করে, তাহলে কি তার শরীরে কোনো ময়লা থাকবে? তারা বললেন, না। তখন তিনি বললেন, পাঁচ ওয়াক্ত সালাতও তেমনি — এর মাধ্যমে আল্লাহ গুনাহ মুছে দেন।', 'সহীহ বুখারী, হাদীস নং ৫২৮; সহীহ মুসলিম, হাদীস নং ৬৬৭', 'অপরিহার্য'),
('দান-সদকায় সম্পদ কমে না', 'রাসূলুল্লাহ (সা.) বলেছেন, সাদাকা দেয়ার কারণে সম্পদ কখনো কমে না।', 'সহীহ মুসলিম, হাদীস নং ২৫৮৮', 'মাঝারি'),
('মায়ের মর্যাদা', 'এক ব্যক্তি রাসূলুল্লাহ (সা.)-কে জিজ্ঞাসা করলেন, আমার উত্তম সঙ্গলাভের সবচেয়ে বেশি হকদার কে? তিনি বললেন, তোমার মা। লোকটি জিজ্ঞাসা করলেন, তারপর কে? তিনি আবার বললেন, তোমার মা। তৃতীয়বারও তিনি বললেন, তোমার মা। চতুর্থবারে বললেন, তারপর তোমার বাবা।', 'সহীহ বুখারী, হাদীস নং ৫৯৭১; সহীহ মুসলিম, হাদীস নং ২৫৪৮', 'অপরিহার্য'),
('গীবত থেকে বিরত থাকা', 'রাসূলুল্লাহ (সা.) জিজ্ঞাসা করলেন, তোমরা কি জানো গীবত কী? সাহাবীরা বললেন, আল্লাহ ও তাঁর রাসূলই ভালো জানেন। তিনি বললেন, তোমার ভাইয়ের এমন কিছু উল্লেখ করা যা সে অপছন্দ করে।', 'সহীহ মুসলিম, হাদীস নং ২৫৮৯', 'গুরুত্বপূর্ণ');
